INSERT OR IGNORE INTO innovation_theory (id, name_ja, name_en, definition, impact_summary, subfield, category, school_of_thought, era_start, schumpeter_layer, innovation_type, cognitive_mechanism, key_researchers, key_works, keywords_ja, keywords_en) VALUES
('inno_diff_441','デジタルウォレット採用の国際比較研究','International Comparative Research on Digital Wallet Adoption','Apple Pay・Google Pay・Alipay・PayPayなどデジタルウォレットの国際比較採用研究。文化的なキャッシュ嗜好・加盟店普及率・セキュリティ設計・ポイント還元が採用速度の国際差を説明することが示された。','グローバルキャッシュレス政策と決済インフラ標準化に実証的根拠を提供した。','diffusion_adoption_user','C_processes','デジタル決済採用研究','2017','meso','adoption','cashless_cultural_adoption','["Liébana-Cabanillas, F.", "Sánchez-Fernández, J.", "Muñoz-Leiva, F."]','["Liébana-Cabanillas et al. (2014) Mobile payment adoption", "Sánchez-Fernández et al. (2018) Digital wallet cross-cultural"]','デジタルウォレット,キャッシュレス,Apple Pay,国際比較','digital wallet,cashless,Apple Pay,international comparison'),
('inno_diff_442','AIコンテンツモデレーション採用研究','AI Content Moderation Adoption Research','SNS・動画プラットフォームでのAI自動モデレーションへのプラットフォーム採用と利用者受容を分析した研究群。誤検知率・言論の自由・人間監督の役割・多言語対応が採用規定因として確認されている。','プラットフォーム規制政策（DSA・Twitter Blue等）とコンテンツガバナンス設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','AIモデレーション採用研究','2019','meso','adoption','content_governance_adoption','["Roberts, S.T.", "Gillespie, T.", "Gorwa, R."]','["Roberts (2019) Behind the Screen", "Gorwa et al. (2020) Algorithmic content moderation"]','AIモデレーション,コンテンツ自動審査,DSA,プラットフォーム規制','AI moderation,automated content review,DSA,platform regulation'),
('inno_diff_443','プログラマブルマター採用の研究フロンティア','Programmable Matter Adoption Research Frontier','形状変化・自己修復・自己組み立てなどプログラマブルマター技術の研究者・早期産業採用を分析した探索的研究群。材料コスト・エネルギー要件・制御複雑性・倫理的懸念が採用規定因として確認されている。','ナノテクノロジー・ソフトロボット産業政策と素材科学研究への投資方向性に初期知見を提供した。','diffusion_adoption_user','C_processes','フロンティア技術採用研究','2020','meso','adoption','frontier_material_adoption','["Toffoli, T.", "Margolus, N.", "Goldstein, S.C."]','["Toffoli & Margolus (1991) Programmable matter concepts", "Goldstein et al. (2005) Programmable matter"]','プログラマブルマター,自己組み立て,ソフトロボット,ナノマテリアル','programmable matter,self-assembly,soft robotics,nanomaterials'),
('inno_diff_444','コーポレートベンチャーキャピタル採用研究','Corporate Venture Capital Adoption Research','事業会社のCVC（コーポレートベンチャーキャピタル）設立・スタートアップ投資採用を分析した研究群。戦略的学習動機・財務リターン目標のバランス・内部抵抗・投資スピード不適合が採用規定因として確認されている。','オープンイノベーション政策と大企業スタートアップ連携促進に実証的根拠を提供した。','diffusion_adoption_user','C_processes','CVC採用研究','2012','meso','adoption','corporate_venturing_adoption','["Chesbrough, H.", "Dushnitsky, G.", "Wadhwa, A."]','["Chesbrough (2002) Making Sense of CVC", "Dushnitsky & Lenox (2005) CVC knowledge creation"]','CVC,コーポレートベンチャー,スタートアップ投資,オープンイノベーション','CVC,corporate venture capital,startup investment,open innovation'),
('inno_diff_445','ディープフェイク検出技術採用研究','Deepfake Detection Technology Adoption Research','動画・音声ディープフェイク検出AIへのメディア機関・SNSプラットフォーム・選挙管理機関採用を分析した研究群。検出精度の限界・GAN軍拡競争・コンテンツ出所証明との統合が採用規定因として確認されている。','偽情報対策政策とメディアリテラシー教育に実証的根拠を提供した。','diffusion_adoption_user','C_processes','偽情報対策技術採用研究','2020','meso','adoption','media_integrity_adoption','["Tolosana, R.", "Vera-Rodriguez, R.", "Fierrez, J."]','["Tolosana et al. (2020) Deepfakes detection survey", "Rossler et al. (2019) FaceForensics++"]','ディープフェイク検出,偽情報対策,コンテンツ真正性,GAN','deepfake detection,disinformation countermeasures,content authenticity,GAN'),
('inno_diff_446','スペースデブリ除去技術採用研究','Space Debris Removal Technology Adoption Research','アクティブデブリ除去（ADR）技術への宇宙機関・商業宇宙企業採用を分析した研究群。費用対効果・軌道環境の国際共有財問題・技術実証段階・法的枠組み不在が採用規定因として確認されている。','宇宙環境ガバナンス政策と持続可能な宇宙利用戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','宇宙環境技術採用研究','2019','meso','adoption','space_commons_adoption','["Liou, J.C.", "Johnson, N.L.", "Bonnal, C."]','["Liou & Johnson (2009) Risks in space", "Bonnal et al. (2013) Active debris removal"]','スペースデブリ,ADR,宇宙環境,軌道ガバナンス','space debris,ADR,space environment,orbital governance'),
('inno_diff_447','量子機械学習採用の初期市場研究','Early Market Research on Quantum Machine Learning Adoption','QML（量子機械学習）アルゴリズムの金融・製薬・物流分野への早期採用を分析した探索的研究群。量子ハードウェアのノイズ問題・古典MLとの比較優位証明・専門人材不足が採用規定因として確認されている。','量子コンピューティング産業政策とAI量子融合研究投資に初期知見を提供した。','diffusion_adoption_user','C_processes','量子AI採用初期研究','2022','meso','adoption','quantum_ai_adoption','["Biamonte, J.", "Wittek, P.", "Pancotti, N."]','["Biamonte et al. (2017) Quantum machine learning", "Cerezo et al. (2022) Challenges variational QML"]','量子機械学習,QML,量子AI,NISQ時代','quantum machine learning,QML,quantum AI,NISQ era'),
('inno_diff_448','デジタル治験採用研究（DCT）','Decentralized Clinical Trial Adoption Research','在宅参加・eConsent・ウェアラブルデータ収集を組み合わせたDCT（分散型臨床試験）への製薬企業・CRO採用を分析した研究群。患者多様性向上・規制ガイドライン未整備・データ品質・サイト不要化への抵抗が採用規定因として確認されている。','治験効率化政策とCOVID-19後の医薬品開発加速戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','分散型治験採用研究','2020','meso','adoption','decentralized_trial_adoption','["Forrest, J.N.", "Lockey, R.", "Sperou, K."]','["Forrest et al. (2022) DCT adoption", "FDA (2021) Decentralized clinical trials guidance"]','DCT,分散型治験,eConsent,ウェアラブル治験','DCT,decentralized clinical trial,eConsent,wearable clinical trial'),
('inno_diff_449','ピアツーピアエネルギー取引採用研究','Peer-to-Peer Energy Trading Adoption Research','ブロックチェーンベースのP2P電力取引プラットフォームへのソーラー自家発電家庭・地域エネルギーコミュニティ採用を分析した研究群。取引の複雑性・電力会社との関係・系統容量制約・価格プレミアム期待が採用規定因として確認されている。','エネルギー民主主義政策と次世代電力市場設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','P2Pエネルギー採用研究','2017','meso','adoption','p2p_energy_adoption','["Sousa, T.", "Soares, T.", "Pinson, P."]','["Sousa et al. (2019) P2P energy trading review", "Pinson et al. (2017) Trading agents energy"]','P2Pエネルギー,電力取引,ブロックチェーン電力,分散エネルギー','P2P energy,electricity trading,blockchain energy,distributed energy'),
('inno_diff_450','知的財産権デジタル管理採用研究','Digital IP Rights Management Adoption Research','ブロックチェーンNFTベースの著作権管理・特許ライセンスデジタル化・デジタル権利管理（DRM）への権利者・プラットフォーム採用を分析した研究群。著作権法との整合・技術的障壁・ユーザー不便が採用規定因として確認されている。','デジタル著作権政策とクリエイターエコノミー保護法制に実証的根拠を提供した。','diffusion_adoption_user','C_processes','デジタルIP管理採用研究','2018','meso','adoption','ip_digital_adoption','["Belleflamme, P.", "Peitz, M.", "Seltzer, W."]','["Belleflamme & Peitz (2014) Digital piracy", "Seltzer (2010) DRM"]','デジタル著作権管理,DRM,NFT著作権,IP管理','digital rights management,DRM,NFT copyright,IP management'),
('inno_diff_451','オープンバンキング採用研究','Open Banking Adoption Research','PSD2・CDR等規制主導のオープンバンキングAPIへの銀行・フィンテック・消費者採用を分析した研究群。データ共有同意管理・セキュリティ・フィンテックへの切替コスト・利便性が採用規定因として確認されている。','金融データポータビリティ政策と競争的金融市場設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','オープンバンキング採用研究','2018','meso','adoption','open_finance_adoption','["Brodsky, L.", "Oakes, L.", "Zachariadis, M."]','["Brodsky & Oakes (2017) Open banking", "Zachariadis & Ozcan (2017) Open banking PSD2"]','オープンバンキング,PSD2,金融API,データポータビリティ','open banking,PSD2,financial API,data portability'),
('inno_diff_452','AIアート採用の美術市場研究','Art Market Research on AI Art Adoption','AIジェネレーティブアート・アルゴリズム絵画・NFTアートへのギャラリー・オークション・コレクター採用を分析した研究群。芸術的価値認識・著作権・創作者アイデンティティ・価格形成が採用規定因として確認されている。','アート市場規制とクリエイティブ産業のAI倫理政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','AIアート採用研究','2021','micro','adoption','aesthetic_ai_adoption','["Elgammal, A.", "Liu, B.", "Elhoseiny, M."]','["Elgammal et al. (2017) CAN creative adversarial networks", "Cetinic & She (2022) Understanding AI art"]','AIアート,生成アート,NFTアート,美術市場','AI art,generative art,NFT art,art market'),
('inno_diff_453','スマート包装採用研究','Smart Packaging Adoption Research','QRコード・NFC・IoTセンサー内蔵のスマート包装への食品・医薬品・物流企業採用を分析した研究群。製造コスト・消費者スキャン率・データ活用計画・廃棄物問題が採用規定因として確認されている。','食品安全政策とサプライチェーントレーサビリティ設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','スマート包装採用研究','2017','meso','adoption','smart_packaging_adoption','["Vanderroost, M.", "Ragaert, P.", "Devlieghere, F."]','["Vanderroost et al. (2014) Smart food packaging", "Ragaert et al. (2017) Active intelligent packaging"]','スマート包装,IoT包装,QRコード食品,トレーサビリティ','smart packaging,IoT packaging,QR code food,traceability'),
('inno_diff_454','デジタルセーフティネット採用研究','Digital Safety Net Adoption Research','オンライン失業給付申請・デジタル社会保障・マイナポータル等デジタル社会インフラへの市民採用を分析した研究群。デジタルデバイド・緊急時アクセス・本人確認の複雑性・情報漏洩不安が採用規定因として確認されている。','社会保障デジタル化政策と行政DXの包摂性設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','社会保障DX採用研究','2015','meso','adoption','social_safety_digital_adoption','["Bovens, M.", "Zouridis, S.", "Buffat, A."]','["Bovens & Zouridis (2002) Street-level to system-level bureaucracy", "Buffat (2015) Street-level bureaucracy digital"]','デジタル社会保障,失業給付,マイナポータル,行政DX','digital social security,unemployment benefit,My Number Portal,government DX'),
('inno_diff_455','モバイル農業保険採用研究','Mobile Agricultural Insurance Adoption Research','スマートフォンを通じた農業保険加入・保険金請求処理への途上国農家採用を分析した研究群。モバイルリテラシー・保険リテラシー・エージェントネットワーク・リモートセンシング審査が採用規定因として確認されている。','農業保険のデジタル化政策と農村金融包摂戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','モバイル農業保険採用研究','2017','micro','adoption','mobile_insurance_adoption','["Ndegwa, G.", "Kinyangi, J.", "Carter, M.R."]','["Ndegwa et al. (2020) Mobile insurance Kenya", "Carter et al. (2017) Agricultural insurance design"]','モバイル農業保険,農業保険,途上国金融,リモートセンシング審査','mobile agricultural insurance,farm insurance,developing country finance,remote sensing assessment'),
('inno_diff_456','光計算・光コンピューティング採用研究','Photonic Computing Adoption Research','光集積回路・シリコンフォトニクス・光コンピュータへのデータセンター・AI計算企業採用を分析した研究群。エネルギー効率・チップ製造歩留まり・プログラム可能性限界・CMOS統合が採用規定因として確認されている。','AI計算インフラ政策と半導体産業の次世代戦略に初期知見を提供した。','diffusion_adoption_user','C_processes','光計算採用初期研究','2021','meso','adoption','photonic_computing_adoption','["Shastri, B.J.", "Tait, A.N.", "Ferreira de Lima, T."]','["Shastri et al. (2021) Photonics for AI", "Tait et al. (2017) Neuromorphic photonic networks"]','光コンピューティング,シリコンフォトニクス,AIチップ,エネルギー効率','photonic computing,silicon photonics,AI chip,energy efficiency'),
('inno_diff_457','アダプティブラーニング採用研究','Adaptive Learning Technology Adoption Research','Knewton・Carnegie Learning・SmartSparrowなどアダプティブラーニング技術への教育機関採用を分析した研究群。学習分析精度・カリキュラムとの整合・教師役割の変容・コストが採用規定因として確認されている。','個別最適化教育政策とEdTech産業の発展に実証的根拠を提供した。','diffusion_adoption_user','C_processes','アダプティブラーニング採用研究','2014','meso','adoption','personalized_learning_adoption','["Pane, J.F.", "Steiner, E.D.", "Baird, M.D."]','["Pane et al. (2015) Continued progress adaptive learning", "VanLehn (2011) Relative effectiveness ITS"]','アダプティブラーニング,個別最適化教育,学習分析,Knewton','adaptive learning,personalized education,learning analytics,Knewton'),
('inno_diff_458','感染症サーベイランスデジタル化採用研究','Digital Infectious Disease Surveillance Adoption Research','EHRデータ・SNS分析・廃水サーベイランスを組み合わせたデジタル感染症監視システムへの保健機関採用を分析した研究群。データ品質・プライバシー・国際情報共有（IHR）・リソース制約が採用規定因として確認されている。','感染症予防政策とグローバルヘルスセキュリティ体制強化に実証的根拠を提供した。','diffusion_adoption_user','C_processes','デジタル感染症監視採用研究','2014','meso','adoption','epidemiological_surveillance_adoption','["Brownstein, J.S.", "Freifeld, C.C.", "Madoff, L.C."]','["Brownstein et al. (2008) HealthMap", "Freifeld et al. (2008) Digital disease surveillance"]','感染症サーベイランス,廃水監視,デジタル疫学,IHR','infectious disease surveillance,wastewater monitoring,digital epidemiology,IHR'),
('inno_diff_459','エネルギー貧困解消技術採用研究','Energy Poverty Alleviation Technology Adoption Research','ペイ・アズ・ユー・ゴー型ソーラーランタン・家庭用ソーラーシステムへのアフリカ・アジア低所得層採用を分析した研究群。マイクロファイナンス連携・支払い方法設計・技術耐久性・修理サービスアクセスが採用規定因として確認されている。','SDG7（クリーンエネルギーへのアクセス）政策と社会的企業の普及戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','エネルギー貧困採用研究','2013','micro','adoption','paygo_adoption','["Lee, K.", "Brewer, E.", "Christiani, C."]','["Lee et al. (2016) PAYGO solar adoption", "Brewer et al. (2005) Energy for developing world"]','エネルギー貧困,PAYGOソーラー,家庭用ソーラー,低所得層採用','energy poverty,PAYGO solar,home solar system,low-income adoption'),
('inno_diff_460','ゲノムデータバンク参加採用研究','Genomic Data Bank Participation Adoption Research','UK Biobank・All of Us・東北メディカルメガバンクへの市民参加採用を分析した研究群。利他的動機・研究貢献感・プライバシー・保険差別懸念・フィードバック期待が採用規定因として確認されている。','精密医療データ基盤整備政策と生命倫理法制設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','ゲノムデータバンク採用研究','2014','micro','adoption','altruistic_biobank_adoption','["Sudlow, C.", "Gallacher, J.", "Allen, N."]','["Sudlow et al. (2015) UK Biobank", "All of Us Research Program (2019)"]','ゲノムデータバンク,バイオバンク,精密医療基盤,参加同意','genomic data bank,biobank,precision medicine infrastructure,participation consent'),
('inno_diff_461','カーボンラベリング採用の食品産業研究','Food Industry Research on Carbon Labeling Adoption','食品製品のCO2排出量ラベル・環境フットプリント表示への食品企業採用と消費者反応を分析した研究群。LCA計算標準・消費者の解釈能力・競合比較の難しさ・コストが採用規定因として確認されている。','フードシステムの脱炭素政策と消費者啓発戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','カーボンラベル採用研究','2019','meso','adoption','carbon_label_adoption','["Upham, P.", "Dendler, L.", "Bleda, M."]','["Upham et al. (2011) Carbon labelling opinion", "Dendler (2014) Sustainability meta-labelling"]','カーボンラベリング,食品排出量,LCA,環境表示','carbon labeling,food emissions,LCA,environmental labeling'),
('inno_diff_462','電動船舶採用研究','Electric Vessel Adoption Research','電動フェリー・電動漁船・電動貨物船への海運会社・港湾管理者採用を分析した研究群。充電インフラ・航続距離・バッテリー重量・IMO脱炭素規制が採用規定因として確認されている。','海運産業の脱炭素政策とゼロエミッション港湾設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','電動船舶採用研究','2019','meso','adoption','maritime_electrification_adoption','["Bouman, E.A.", "Lindstad, E.", "Rialland, A.I."]','["Bouman et al. (2017) State of the art technologies decarbonizing shipping", "IMO (2018) GHG strategy"]','電動船舶,電動フェリー,海運脱炭素,IMOゼロエミッション','electric vessel,electric ferry,maritime decarbonization,IMO zero emission'),
('inno_diff_463','ゼロトラスト採用の政府・公共機関研究','Government and Public Agency Research on Zero Trust Adoption','NIST SP 800-207準拠のゼロトラストアーキテクチャへの政府機関採用を分析した研究群。レガシーシステム統合・予算制約・変更管理・クラウド移行との同期が採用規定因として確認されている。','国家サイバーセキュリティ戦略と行政クラウド政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','政府セキュリティ採用研究','2020','meso','adoption','government_zt_adoption','["Rose, S.", "Borchert, O.", "Mitchell, S."]','["NIST (2020) SP 800-207 Zero Trust", "CISA (2021) Zero Trust Maturity Model"]','ゼロトラスト,政府セキュリティ,NIST,サイバー防衛','zero trust,government security,NIST,cyber defense'),
('inno_diff_464','空間コンピューティング採用研究（Apple Vision Pro）','Spatial Computing Adoption Research: Apple Vision Pro','Apple Vision Pro等空間コンピューティングデバイスへの初期採用者・企業採用を分析した研究群。装着不快感・価格・キラーアプリ不在・社会的文脈不適切感が採用障壁として確認されている。AR/VR採用研究の第三世代として位置づけられる。','空間コンピューティング産業政策とXRデバイス設計標準化に初期知見を提供した。','diffusion_adoption_user','C_processes','空間コンピューティング採用研究','2024','micro','adoption','spatial_computing_adoption','["Apple Inc.", "Milgram, P.", "Kishino, F."]','["Apple (2024) Vision Pro launch", "Milgram & Kishino (1994) Reality-virtuality continuum"]','空間コンピューティング,Apple Vision Pro,XR,没入型コンピューティング','spatial computing,Apple Vision Pro,XR,immersive computing'),
('inno_diff_465','科学技術リテラシーとイノベーション採用の関係研究','Research on Science-Technology Literacy and Innovation Adoption Relationship','科学技術リテラシー（STL）の高低がイノベーション採用速度・批判的評価・リスク認知に与える影響を分析した研究群。STLと採用の関係が線形ではなく、高STLが採用を促進する場合と批判的阻害をもたらす場合の条件を識別した。','科学教育政策とイノベーション普及コミュニケーション戦略に理論的根拠を提供した。','diffusion_adoption_user','C_processes','科学リテラシー採用研究','2008','micro','adoption','scientific_literacy_adoption','["Miller, J.D.", "Norris, S.P.", "Phillips, L.M."]','["Miller (2004) Science literacy measurement", "Norris & Phillips (2003) Scientific literacy"]','科学技術リテラシー,STL,イノベーション採用,リスク認知','science technology literacy,STL,innovation adoption,risk perception'),
('inno_diff_466','ポストコロニアル技術採用研究','Postcolonial Technology Adoption Research','旧植民地諸国での西洋型デジタル技術採用における植民地的知識権力関係・技術主権・ローカル適応の必要性を分析した批判的研究群。技術輸入モデルへの批判・デジタル主権・インディジナスデータ主権が中心テーマとなっている。','グローバルデジタルガバナンスとテクノロジー開発援助政策の批判的再検討に貢献した。','diffusion_adoption_user','C_processes','批判的採用理論','2012','macro','adoption','decolonial_adoption','["Mohamed, S.", "Png, M.T.", "Isaac, W."]','["Mohamed et al. (2020) Decolonial AI", "Couldry & Meijas (2019) Costs of connection"]','ポストコロニアル,デジタル主権,技術輸入,批判的採用研究','postcolonial,digital sovereignty,technology import,critical adoption research'),
('inno_diff_467','コンシューマーゲノミクス採用の後悔研究','Regret Research in Consumer Genomics Adoption','23andMe・AncestryDNA等消費者向けゲノム検査後の採用後悔・利用継続・情報活用困難を分析した研究群。予期せぬ健康リスク情報・家族関係への影響・情報の意味理解困難が後悔規定因として確認されている。','消費者ゲノム検査の事前情報提供設計とインフォームドコンセント政策に貢献した。','diffusion_adoption_user','C_processes','採用後悔・継続研究','2016','micro','adoption','post_adoption_regret','["Green, R.C.", "Roberts, J.S.", "Mittman, I.S."]','["Green et al. (2009) REVEAL study", "Roberts et al. (2011) Return genetic risk results"]','消費者ゲノミクス,採用後悔,遺伝子検査,インフォームドコンセント','consumer genomics,adoption regret,genetic testing,informed consent'),
('inno_diff_468','量子通信ネットワーク都市実証採用研究','Urban Quantum Communication Network Pilot Adoption Research','東京・北京・Delft等都市間量子鍵配送（QKD）ネットワーク実証への政府・企業採用を分析した研究群。ファイバー損失・中継器技術・コスト・既存光ファイバー利用可能性が採用規定因として確認されている。','量子通信インフラ公共投資政策と国家安全保障通信戦略に初期知見を提供した。','diffusion_adoption_user','C_processes','都市量子通信採用研究','2019','meso','adoption','quantum_network_pilot','["Sasaki, M.", "Peev, M.", "Stucki, D."]','["Sasaki et al. (2011) Tokyo QKD network", "Peev et al. (2009) SECOQC Vienna QKD network"]','量子通信都市網,QKDネットワーク,東京量子,光ファイバー量子','urban quantum network,QKD network,Tokyo quantum,fiber quantum'),
('inno_diff_469','クリエイターエコノミーツール採用研究','Creator Economy Tool Adoption Research','Substack・Patreon・note・YouTube Memberships等クリエイターエコノミープラットフォームへのコンテンツクリエイター採用を分析した研究群。収益化モデル・ファン関係管理・プラットフォーム依存リスク・コンテンツ独立性が採用規定因として確認されている。','クリエイターエコノミー規制政策と独立メディア支援に実証的根拠を提供した。','diffusion_adoption_user','C_processes','クリエイターエコノミー採用研究','2019','micro','adoption','creator_monetization_adoption','["Li, F.", "Mäntymäki, M.", "Zhang, X."]','["Li et al. (2021) Creator economy", "Mäntymäki (2022) Subscription platforms"]','クリエイターエコノミー,Patreon,Substack,コンテンツ収益化','creator economy,Patreon,Substack,content monetization'),
('inno_diff_470','バイオ炭（バイオチャー）採用研究','Biochar Adoption Research','バイオ炭の農業・土壌改良・炭素固定への農家・自治体採用を分析した研究群。長期炭素固定効果への不確実性・バイオマス供給・生産コスト・作物収量改善への期待が採用規定因として確認されている。','農業炭素固定政策と土壌健全化戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','農業炭素採用研究','2012','meso','adoption','soil_carbon_adoption','["Lehmann, J.", "Gaunt, J.", "Rondon, M."]','["Lehmann et al. (2006) Biochar as soil amendment", "Gaunt & Lehmann (2008) Biochar carbon mitigation"]','バイオ炭,バイオチャー,炭素固定,農業土壌改良','biochar,carbon sequestration,agricultural soil amendment,carbon farming'),
('inno_diff_471','エキスパートシステム採用の医療診断研究（歴史的）','Historical Research on Expert System Adoption in Medical Diagnosis','MYCIN・INTERNIST-1・DE Xtenシステムなど1970〜1990年代の医療診断エキスパートシステム採用を歴史的に分析した研究群。医師の自律性・説明可能性・入力負担・誤診責任が採用障壁として確認されている。現代医療AIの前史として参照される。','AIシステム採用の歴史的教訓を提供し、現代医療AI採用研究の理論的基盤となった。','diffusion_adoption_user','C_processes','歴史的AI採用研究','1985','meso','adoption','historical_ai_adoption','["Shortliffe, E.H.", "Miller, R.A.", "Clancey, W.J."]','["Shortliffe (1976) MYCIN", "Miller et al. (1982) INTERNIST-1"]','エキスパートシステム,MYCIN,医療診断AI,歴史的AI','expert system,MYCIN,medical diagnostic AI,historical AI'),
('inno_diff_472','デジタルホワイトボード採用研究','Digital Whiteboard Adoption Research','Miro・FigJam・MURAL・Microsoft Whiteboardへの分散チーム採用を分析した研究群。ブレインストーミング効果・タッチ操作性・テンプレート豊富さ・ビデオ会議統合が採用規定因として確認されている。対面ホワイトボードとのハイブリッド使用も研究されている。','分散型イノベーションワークショップ設計とリモートワーク生産性向上に実証的根拠を提供した。','diffusion_adoption_user','C_processes','デジタルコラボレーション採用研究','2019','micro','adoption','digital_whiteboard_adoption','["Munkvold, B.E.", "Zigurs, I.", "Cheng, X."]','["Munkvold & Zigurs (2007) Process and technology", "Cheng et al. (2020) Remote collaboration tools"]','デジタルホワイトボード,Miro,分散チーム,リモートブレスト','digital whiteboard,Miro,distributed team,remote brainstorming'),
('inno_diff_473','コントラクトファーミング採用研究','Contract Farming Adoption Research','食品企業・輸出業者との契約農業への途上国農家採用を分析した研究群。価格リスク低減・技術移転・融資アクセス・契約履行リスクが採用規定因として確認されている。農家の交渉力と食品サプライチェーンガバナンスも重要テーマとなっている。','農業市場連結政策と食料安全保障戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','農業市場連結採用研究','2000','micro','adoption','contract_farming_adoption','["Minot, N.", "Watts, M.", "Warning, M."]','["Minot (1986) Contract farming", "Warning & Key (2002) Ghana contract farming"]','契約農業,コントラクトファーミング,農家市場連結,食品サプライチェーン','contract farming,market linkage,farmer market connection,food supply chain'),
('inno_diff_474','デジタル測定・校正技術採用研究','Digital Measurement and Calibration Technology Adoption Research','スマート測定機器・IoT校正システム・デジタルキャリブレーションサービスへの製造・試験機関採用を分析した研究群。計量法規制・トレーサビリティ要件・遠隔校正受容・品質管理統合が採用規定因として確認されている。','産業計量政策とスマート製造の品質保証体制設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','計量技術採用研究','2016','meso','adoption','metrological_adoption','["Pavese, F.", "Molinar, G.B.", "Woolliams, E.R."]','["Pavese & Molinar (2013) Metrology handbook", "Woolliams et al. (2018) Smart metrology"]','計量技術,デジタル校正,トレーサビリティ,スマート計測','metrology,digital calibration,traceability,smart measurement'),
('inno_diff_475','継続学習とイノベーション採用の関係研究','Research on Continuous Learning and Innovation Adoption Relationship','個人・組織の継続的学習文化（成長マインドセット・心理的安全性）がイノベーション採用速度・拡張的採用・失敗学習に与える影響を分析した研究群。Dweck の成長マインドセット理論とUTAUTを統合した枠組みが提案されている。','企業の学習組織設計と人材育成プログラムに実証的根拠を提供した。','diffusion_adoption_user','C_processes','学習組織採用研究','2010','micro','adoption','growth_mindset_adoption','["Dweck, C.S.", "Senge, P.", "Edmondson, A.C."]','["Dweck (2006) Mindset", "Edmondson (2018) The Fearless Organization"]','継続学習,成長マインドセット,学習組織,心理的安全性','continuous learning,growth mindset,learning organization,psychological safety'),
('inno_diff_476','ビジュアルプログラミング採用研究','Visual Programming Tool Adoption Research','Scratch・MIT App Inventor・Node-REDなどビジュアルプログラミング環境への子ども・非エンジニア採用を分析した研究群。抽象化レベルの適切さ・ゲーム的インタフェース・プロジェクト共有コミュニティが採用規定因として確認されている。','コンピュータ教育政策とSTEAM教育の普及に実証的根拠を提供した。','diffusion_adoption_user','C_processes','コード教育採用研究','2007','micro','adoption','computational_thinking_adoption','["Resnick, M.", "Wing, J.M.", "Scratch Team"]','["Resnick et al. (2009) Scratch programming for all", "Wing (2006) Computational thinking"]','ビジュアルプログラミング,Scratch,コンピュータ教育,STEAM','visual programming,Scratch,computer education,STEAM'),
('inno_diff_477','クリーン調理採用研究（途上国）','Clean Cooking Adoption Research in Developing Countries','改良かまど・LPGコンロ・バイオガスクッカー・電気調理器への途上国家庭採用を分析した研究群。初期コスト・燃料アクセス・調理習慣・屋内空気汚染健康便益認知が採用規定因として確認されている。スタック採用と排除採用のダイナミクスも研究されている。','SDG7達成と途上国保健政策のリンクに実証的根拠を提供した。','diffusion_adoption_user','C_processes','クリーンエネルギー採用研究','2005','micro','adoption','clean_cooking_adoption','["Puzzolo, E.", "Pope, D.", "Brodmann, N."]','["Puzzolo et al. (2016) Clean cooking fuels", "Pope et al. (2017) Household biomass combustion"]','クリーン調理,改良かまど,LPGコンロ,屋内空気汚染','clean cooking,improved cookstove,LPG,indoor air pollution'),
('inno_diff_478','スーパーアプリ採用研究（WeChat・Grab・PayPay）','Super App Adoption Research: WeChat, Grab, PayPay','単一アプリで通信・決済・ショッピング・金融・行政を統合したスーパーアプリへの採用を分析した研究群。エコシステム利便性・プラットフォーム依存リスク・データ独占懸念・文化的受容性が採用規定因として確認されている。','プラットフォーム独禁規制とデジタル経済政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','スーパーアプリ採用研究','2017','micro','adoption','super_app_adoption','["Zhang, K.Z.K.", "Xu, H.", "Zhao, S."]','["Zhang et al. (2020) WeChat super app adoption", "Zhao (2019) Mobile payment ecosystem"]','スーパーアプリ,WeChat,Grab,デジタルエコシステム','super app,WeChat,Grab,digital ecosystem'),
('inno_diff_479','エレクトロニックスポーツ（eスポーツ）プラットフォーム採用研究','Esports Platform Adoption Research','Twitch・Steam・Valorant等eスポーツプラットフォームへの選手・観客採用を分析した研究群。競技性・コミュニティ帰属感・ストリーミング品質・スポンサーシップ文化が採用規定因として確認されている。','eスポーツ産業政策とゲーミングプラットフォーム設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','eスポーツ採用研究','2016','micro','adoption','esports_community_adoption','["Hamari, J.", "Sjöblom, M.", "Jenny, S.E."]','["Hamari & Sjöblom (2017) Why do people watch others play", "Jenny et al. (2017) Virtual sport"]','eスポーツ,Twitch,ゲーム配信,競技ゲーム','esports,Twitch,game streaming,competitive gaming'),
('inno_diff_480','カーボンキャプチャー採用の産業研究（CCUS）','Industrial Research on Carbon Capture Adoption: CCUS','セメント・鉄鋼・化学産業でのCCUS（炭素回収・利用・貯留）技術採用を分析した研究群。地質貯留適地・輸送インフラ・コスト・炭素リーク懸念・政策インセンティブが採用規定因として確認されている。','産業脱炭素政策とカーボンニュートラル技術ロードマップに実証的根拠を提供した。','diffusion_adoption_user','C_processes','CCUS採用研究','2015','meso','adoption','carbon_capture_adoption','["Boot-Handford, M.E.", "Abanades, J.C.", "Anthony, E.J."]','["Boot-Handford et al. (2014) CCUS review", "Bui et al. (2018) Carbon capture utilisation"]','CCUS,炭素回収,CCS,産業脱炭素','CCUS,carbon capture,CCS,industrial decarbonization'),
('inno_diff_481','デジタル化と採用の発展段階モデル','Stage Model of Digitalization and Innovation Adoption','組織のデジタル化成熟度（デジタイゼーション→デジタライゼーション→デジタル変革）と各段階でのイノベーション採用パターンの相互関係を分析したモデル群。Westermanらのデジタル成熟度モデルとRogersの採用理論を統合した枠組みが提案されている。','企業のデジタル変革ロードマップ策定と採用支援政策の段階的設計に理論的根拠を提供した。','diffusion_adoption_user','C_processes','デジタル変革採用理論','2016','meso','adoption','digital_maturity_adoption','["Westerman, G.", "Bonnet, D.", "McAfee, A."]','["Westerman et al. (2014) Leading Digital", "Bonnet & Westerman (2021) Digital growth agenda"]','デジタル変革,デジタル成熟度,デジタライゼーション,採用段階モデル','digital transformation,digital maturity,digitalization,adoption stage model'),
('inno_diff_482','インクルーシブデザインと採用促進研究','Inclusive Design and Adoption Promotion Research','ユニバーサルデザイン・インクルーシブデザイン原則に基づいた製品・サービス設計が多様な利用者（高齢者・障害者・移民等）の採用率向上に与える効果を分析した研究群。設計多様性・アクセシビリティ評価・コスト-採用トレードオフが主要テーマとなっている。','デジタルアクセシビリティ法（EAA・WCAG）とインクルーシブ製品設計の科学的根拠を提供した。','diffusion_adoption_user','C_processes','インクルーシブ採用研究','2010','micro','adoption','inclusive_design_adoption','["Clarkson, P.J.", "Coleman, R.", "Dong, H."]','["Clarkson et al. (2003) Inclusive Design", "Coleman et al. (2003) Design for inclusivity"]','インクルーシブデザイン,ユニバーサルデザイン,アクセシビリティ,採用促進','inclusive design,universal design,accessibility,adoption promotion'),
('inno_diff_483','量子ドット・ペロブスカイト太陽電池採用研究','Quantum Dot and Perovskite Solar Cell Adoption Research','次世代薄膜太陽電池（ペロブスカイト・量子ドット）の製造業・建築業への採用を分析した研究群。変換効率・耐久性・鉛フリー化・大面積製造スケーリングが採用規定因として確認されている。','次世代太陽光発電政策と再生可能エネルギー産業の技術転換戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','次世代太陽電池採用研究','2020','meso','adoption','next_gen_solar_adoption','["Snaith, H.J.", "Saliba, M.", "Nozik, A.J."]','["Snaith (2013) Perovskites solar cells", "Nozik et al. (2010) Semiconductor quantum dots solar"]','ペロブスカイト,量子ドット太陽電池,次世代太陽光,薄膜PV','perovskite,quantum dot solar cell,next-generation solar,thin-film PV'),
('inno_diff_484','空港自動化技術採用研究','Airport Automation Technology Adoption Research','自動チェックイン・自動手荷物預け・e-Gate・空港ロボットへの空港運営者・旅客採用を分析した研究群。キュー短縮効果・セキュリティ精度・言語対応・旅客年齢層別不安が採用規定因として確認されている。','空港運営効率化政策と旅客体験設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','空港自動化採用研究','2014','meso','adoption','airport_automation_adoption','["Liljander, V.", "Gillberg, F.", "Gummerus, J."]','["Liljander et al. (2006) Self-service technologies airport", "Gillberg & Strandvik (2019) Airport digital"]','空港自動化,自動チェックイン,e-Gate,旅客体験','airport automation,self-service check-in,e-Gate,passenger experience'),
('inno_diff_485','原子力発電採用の社会的受容研究','Nuclear Power Social Acceptance Research','SMR（小型モジュール炉）・第四世代原子炉への社会的受容と政策採用を分析した研究群。フクシマ後の恐怖記憶・廃棄物処理・気候変動緩和便益・地域雇用が受容規定因として確認されている。','原子力政策と気候変動対策のエネルギーポートフォリオ設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','原子力受容研究','2011','macro','adoption','nuclear_public_acceptance','["Ho, S.S.", "Leong, A.D.", "Looi, J."]','["Ho et al. (2019) Public perception nuclear", "OECD NEA (2020) Nuclear public acceptance"]','原子力,SMR,社会的受容,廃棄物処理','nuclear power,SMR,social acceptance,waste management'),
('inno_diff_486','バーティカルSaaS採用研究','Vertical SaaS Adoption Research','医療・法律・建設・農業等特定産業向け垂直型SaaSへの中小企業採用を分析した研究群。汎用SaaSとの差別化・ドメイン知識組み込み・乗り換えコスト・ベンダー持続性懸念が採用規定因として確認されている。','特化型ソフトウェア市場の発展と産業デジタル化政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','垂直型SaaS採用研究','2016','meso','adoption','vertical_saas_adoption','["Bosworth, M.", "Holland, B.", "Harrington, M."]','["Bosworth et al. (2021) Vertical SaaS guide", "a16z (2020) Vertical SaaS market"]','垂直型SaaS,産業特化ソフトウェア,中小企業DX,ドメイン特化','vertical SaaS,industry-specific software,SME DX,domain-specific'),
('inno_diff_487','プログラマブルロジックコントローラ（PLC）近代化採用研究','PLC Modernization Adoption Research','レガシーPLCのソフトPLC・クラウドPLC・IIoT統合型PLCへの製造業採用を分析した研究群。生産停止リスク・後方互換性・エンジニアの再訓練・ベンダーロックインが採用規定因として確認されている。','製造業のOTセキュリティとスマートファクトリー化戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','産業制御システム採用研究','2018','meso','adoption','plc_modernization_adoption','["Lewis, R.W.", "Berger, H.", "Christensen, E.R."]','["Lewis (1998) Programmable Logic Controllers", "Berger (2006) Automating with SIMATIC"]','PLC,ソフトPLC,IIoT,OT近代化','PLC,soft PLC,IIoT,OT modernization'),
('inno_diff_488','脳波デバイスによる感情計測採用研究','Brainwave Device for Affective Computing Adoption Research','消費者向けEEGヘッドバンド（Muse・Emotiv）による感情・集中力モニタリングツールへの採用を分析した研究群。計測精度・ウェアラブル不快感・感情データプライバシー・神経倫理が採用規定因として確認されている。','ニューロテクノロジー規制と感情AI倫理設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','感情コンピューティング採用研究','2016','micro','adoption','affective_computing_adoption','["Picard, R.W.", "Hasson, U.", "Zander, T.O."]','["Picard (1997) Affective Computing", "Zander & Kothe (2011) Passive BCI"]','EEGヘッドバンド,感情計測,ニューロテク,感情AI','EEG headband,affective measurement,neurotech,affective AI'),
('inno_diff_489','クロスボーダーEコマース採用研究','Cross-Border E-Commerce Adoption Research','Shopify・AliExpress・Amazon Global等を通じた越境ECの中小企業セラー採用を分析した研究群。通関手続き・関税・返品ロジスティクス・多言語カスタマーサポート・国際決済が採用規定因として確認されている。','越境EC政策と中小企業グローバル化支援に実証的根拠を提供した。','diffusion_adoption_user','C_processes','越境EC採用研究','2015','meso','adoption','cross_border_ecommerce_adoption','["Wigand, R.T.", "Benjamin, R.I.", "Birkland, J.L.H."]','["Wigand et al. (2008) E-commerce cross-border", "OECD (2020) E-commerce trade"]','越境EC,クロスボーダー,国際Eコマース,SME国際化','cross-border e-commerce,international e-commerce,global trade,SME internationalization'),
('inno_diff_490','デジタルファッション採用研究','Digital Fashion Adoption Research','バーチャルファッション（Decentraland・Snapchat ARフィルター）・デジタル試着・AI生成ファッションデザインへの消費者・ブランド採用を分析した研究群。アイデンティティ表現・サステナビリティ動機・所有感覚・現実世界価値との乖離が採用規定因として確認されている。','ファッション産業のメタバース戦略とデジタル消費者行動研究に実証的根拠を提供した。','diffusion_adoption_user','C_processes','デジタルファッション採用研究','2021','micro','adoption','virtual_fashion_adoption','["Särmäkari, N.", "Vänskä, A.", "Turney, J."]','["Särmäkari (2022) Digital fashion", "Vänskä (2020) Virtuality fashion"]','デジタルファッション,バーチャルファッション,AR試着,メタバースファッション','digital fashion,virtual fashion,AR try-on,metaverse fashion'),
('inno_diff_491','デジタルジャーナリズムツール採用研究','Digital Journalism Tool Adoption Research','データジャーナリズム・AIニュース生成・ドローンジャーナリズム・ライブSNS報道へのジャーナリスト・編集者採用を分析した研究群。ジャーナリズム規範・倫理・技術スキル習得・読者エンゲージメントが採用規定因として確認されている。','報道機関のデジタル変革戦略とジャーナリズム教育改革に実証的根拠を提供した。','diffusion_adoption_user','C_processes','デジタルジャーナリズム採用研究','2013','micro','adoption','journalism_digital_adoption','["Coddington, M.", "Lewis, S.C.", "Steensen, S."]','["Coddington (2015) Data journalism", "Lewis & Westlund (2015) Big data journalism"]','データジャーナリズム,AIニュース,ドローンジャーナリズム,デジタル報道','data journalism,AI news,drone journalism,digital news'),
('inno_diff_492','ナチュラルユーザーインタフェース採用研究（ジェスチャー・視線）','Natural User Interface Adoption Research: Gesture and Eye Tracking','Kinect・LeapMotion・Eye Tracking（Tobii等）などジェスチャー・視線制御インタフェースへの採用を分析した研究群。学習容易性・疲労（ゴリラアーム問題）・精度・アプリケーション文脈適合性が採用規定因として確認されている。','アクセシビリティ技術設計とXRインタフェース開発に実証的根拠を提供した。','diffusion_adoption_user','C_processes','自然UI採用研究','2010','micro','adoption','gesture_ui_adoption','["Wigdor, D.", "Wixon, D.", "Mistry, P."]','["Wigdor & Wixon (2011) Brave NUI World", "Mistry & Maes (2009) SixthSense"]','ジェスチャーUI,視線追跡,自然ユーザーインタフェース,Kinect','gesture UI,eye tracking,natural user interface,Kinect'),
('inno_diff_493','マルチモーダルAI採用研究','Multimodal AI Adoption Research','GPT-4V・Gemini Ultra・Claude Vision等テキスト・画像・音声を統合処理するマルチモーダルAIへの企業・個人採用を分析した研究群。専門性要求の変化・既存ワークフロー適合・コスト・プライバシーが採用規定因として確認されている。2024年以降の最新研究群が蓄積されている。','マルチモーダルAI規制政策と企業のAI活用戦略設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','マルチモーダルAI採用研究','2023','micro','adoption','multimodal_ai_adoption','["OpenAI", "Google DeepMind", "Anthropic"]','["OpenAI (2023) GPT-4V system card", "Google (2023) Gemini multimodal"]','マルチモーダルAI,GPT-4V,Gemini,画像認識AI','multimodal AI,GPT-4V,Gemini,image recognition AI'),
('inno_diff_494','海洋再生可能エネルギー採用研究','Ocean Renewable Energy Adoption Research','洋上風力・波力・潮力発電への電力会社・投資家採用を分析した研究群。海洋環境許認可・漁業権との調整・塩害耐久性・グリッド連系コストが採用規定因として確認されている。','洋上再生可能エネルギー政策と沿岸地域開発戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','海洋エネルギー採用研究','2015','meso','adoption','ocean_energy_adoption','["Magagna, D.", "Uihlein, A.", "Dalton, G."]','["Magagna & Uihlein (2015) Ocean energy development", "Dalton et al. (2010) Wave energy conversion"]','洋上風力,波力発電,潮力発電,海洋再生エネルギー','offshore wind,wave energy,tidal energy,ocean renewable energy'),
('inno_diff_495','チャットコマース採用研究','Chat Commerce Adoption Research','WhatsApp Business・LINE Official Account・WeChat商取引などチャットアプリを通じた商取引への企業・消費者採用を分析した研究群。対話的購買体験・カスタマーサービス統合・支払い埋め込み・スパム回避が採用規定因として確認されている。','会話型コマース政策とメッセージングプラットフォーム規制設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','チャットコマース採用研究','2018','micro','adoption','conversational_commerce_adoption','["Brandtzaeg, P.B.", "Følstad, A.", "Feine, J."]','["Brandtzaeg & Følstad (2017) Chatbots", "Feine et al. (2019) Chatbot adoption"]','チャットコマース,WhatsApp商取引,会話型コマース,メッセージング購買','chat commerce,WhatsApp business,conversational commerce,messaging shopping'),
('inno_diff_496','環境DNAモニタリング採用の行政研究','Government Agency Research on eDNA Monitoring Adoption','EU・米国・日本の環境省庁による環境DNA（eDNA）水質・生物多様性モニタリング技術の行政採用を分析した研究群。標準化・法的証拠能力・従来調査手法との比較・コスト削減可能性が採用規定因として確認されている。','生物多様性政策モニタリングと環境規制執行の近代化に実証的根拠を提供した。','diffusion_adoption_user','C_processes','政府環境技術採用研究','2018','meso','adoption','regulatory_monitoring_adoption','["Thomsen, P.F.", "Willerslev, E.", "Harper, L.R."]','["Thomsen & Willerslev (2015) Environmental DNA", "Harper et al. (2019) eDNA for government"]','環境DNA,eDNAモニタリング,生物多様性行政,水質調査','environmental DNA,eDNA monitoring,biodiversity governance,water quality survey'),
('inno_diff_497','ニューロフィードバック採用研究','Neurofeedback Adoption Research','EEGニューロフィードバック（ADHD・PTSD・不安障害治療）の臨床家・患者採用を分析した研究群。エビデンスの不確実性・保険適用・訓練期間・プラセボ効果懸念が採用規定因として確認されている。','メンタルヘルス治療政策と神経リハビリ医療保険設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','ニューロフィードバック採用研究','2010','micro','adoption','clinical_neurofeedback_adoption','["Arns, M.", "Heinrich, H.", "Strehl, U."]','["Arns et al. (2009) Neurofeedback ADHD", "Heinrich et al. (2007) Neurofeedback review"]','ニューロフィードバック,EEG治療,ADHD,神経リハビリ','neurofeedback,EEG treatment,ADHD,neural rehabilitation'),
('inno_diff_498','アンビエントコンピューティング採用研究','Ambient Computing Adoption Research','Amazon Alexa・Google Nest・Apple HomePodなどアンビエントコンピューティングデバイスへの家庭採用を分析した研究群。常時接続への信頼・音声記録プライバシー・ハブとしての利便性・相互運用性が採用規定因として確認されている。','スマートホーム政策とIoTプライバシー規制設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','アンビエントコンピューティング採用研究','2015','micro','adoption','ambient_computing_adoption','["Weiser, M.", "Gregor, S.", "Bohm, M."]','["Weiser (1991) Computer for 21st century", "Gregor & Bohm (2010) Ambient information"]','アンビエントコンピューティング,スマートホーム,常時接続,IoTプライバシー','ambient computing,smart home,always-on,IoT privacy'),
('inno_diff_499','3D映像技術採用研究（映画・医療・教育）','3D Imaging Technology Adoption Research: Film, Medical, Education','立体映像（3Dシネマ・裸眼3D・3D医療映像・3D教育コンテンツ）の各セクター採用を分析した研究群。眼疲労・コスト・コンテンツ不足・2D比較優位の不明確さが採用規定因として確認されている。3Dシネマ普及後衰退のサイクルも研究されている。','コンテンツ産業投資判断と医療画像診断設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','3D映像採用研究','2010','meso','adoption','3d_visualization_adoption','["Zone, R.", "Woods, R.L.", "Lenny, B."]','["Zone (2007) Stereoscopic cinema", "Woods (2012) 3D displays"]','3D映像,立体映像,3Dシネマ,裸眼3D','3D imaging,stereoscopic,3D cinema,glasses-free 3D'),
('inno_diff_500','エネルギー貯蔵技術採用（グリッド規模蓄電）','Grid-Scale Energy Storage Technology Adoption','流体電池・圧縮空気貯蔵・揚水発電・リチウムイオン大型ESS等グリッド規模蓄電システムへの電力会社採用を分析した研究群。サイクル寿命・コスト・場所制約・規制不整備が採用規定因として確認されている。','再生可能エネルギー統合政策とグリッド安定化戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','グリッド蓄電採用研究','2015','meso','adoption','grid_storage_adoption','["Dunn, B.", "Kamath, H.", "Tarascon, J.M."]','["Dunn et al. (2011) Electrical energy storage", "Tarascon & Armand (2001) Battery issues"]','グリッド蓄電,流体電池,圧縮空気貯蔵,ESS採用','grid storage,flow battery,compressed air storage,ESS adoption'),
('inno_diff_501','マイクロファイナンス採用研究（デジタル化後）','Digital-Era Microfinance Adoption Research','スマートフォンアプリ・モバイルマネー連携型マイクロファイナンスへの途上国起業家採用を分析した研究群。スコアリングアルゴリズム信頼・グループ連帯責任からの転換・デジタルリテラシー・過剰負債リスクが採用規定因として確認されている。','デジタルマイクロファイナンス政策と金融包摂のデジタル移行に実証的根拠を提供した。','diffusion_adoption_user','C_processes','デジタルマイクロファイナンス採用研究','2014','micro','adoption','digital_microfinance_adoption','["Karlan, D.", "Zinman, J.", "Dupas, P."]','["Karlan & Zinman (2008) Credit elasticity microfinance", "Dupas & Robinson (2013) Savings sub-Saharan Africa"]','デジタルマイクロファイナンス,モバイル融資,途上国金融,金融包摂','digital microfinance,mobile lending,developing country finance,financial inclusion'),
('inno_diff_502','人工光合成・太陽化学採用研究','Artificial Photosynthesis and Solar Chemistry Adoption Research','太陽光駆動の水分解水素製造・CO2還元・ソーラーフュエル技術への研究機関・エネルギー企業採用を分析した研究群。光触媒効率・スケールアップ・製造コスト・安全性が採用規定因として確認されている。','グリーン水素・太陽化学産業政策と長期エネルギーロードマップに初期知見を提供した。','diffusion_adoption_user','C_processes','太陽化学採用初期研究','2018','meso','adoption','solar_chemical_adoption','["Nocera, D.G.", "Lewis, N.S.", "Yablonovitch, E."]','["Nocera (2012) Artificial leaf", "Lewis (2016) Research opportunities solar fuel"]','人工光合成,ソーラーフュエル,光触媒水素,グリーン水素','artificial photosynthesis,solar fuels,photocatalytic hydrogen,green hydrogen'),
('inno_diff_503','仮想発電所（VPP）採用研究','Virtual Power Plant Adoption Research','分散型太陽光・蓄電池・EV・HEMSをAIで統合制御する仮想発電所への電力会社・アグリゲーター採用を分析した研究群。参加者リクルート・需給予測精度・規制インセンティブ・ITプラットフォーム整備が採用規定因として確認されている。','分散型エネルギーリソース管理政策と次世代電力市場設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','VPP採用研究','2017','meso','adoption','vpp_adoption','["Pudjianto, D.", "Ramsay, C.", "Strbac, G."]','["Pudjianto et al. (2007) Virtual power plant", "Strbac et al. (2012) Smart grid technologies"]','仮想発電所,VPP,分散エネルギー,需給調整','virtual power plant,VPP,distributed energy resources,demand response'),
('inno_diff_504','電子廃棄物（E-waste）管理技術採用研究','E-Waste Management Technology Adoption Research','都市鉱山回収・E-waste認証リサイクル・IoTトラッキング付き廃棄物管理システムへの企業・自治体採用を分析した研究群。拡大生産者責任（EPR）規制・回収コスト・貴金属回収経済性が採用規定因として確認されている。','E-waste規制政策と循環経済推進に実証的根拠を提供した。','diffusion_adoption_user','C_processes','E-waste採用研究','2015','meso','adoption','ewaste_management_adoption','["Baldé, C.P.", "Forti, V.", "Kumar, V."]','["Baldé et al. (2017) E-waste monitor", "Forti et al. (2020) Global e-waste monitor"]','E-waste,電子廃棄物,都市鉱山,拡大生産者責任','e-waste,electronic waste,urban mining,extended producer responsibility'),
('inno_diff_505','組織の両利き経営とイノベーション採用','Ambidextrous Organization and Innovation Adoption','既存事業の深化（exploitation）と新規技術の探索（exploration）を同時追求する両利き経営において、破壊的イノベーションの採用決定がどのようにガバナンスされるかを分析した研究群。組織構造・リーダーシップスタイル・資源配分が採用規定因として確認されている。','大企業のデジタル変革組織設計と新規事業採用ガバナンスに理論的根拠を提供した。','diffusion_adoption_user','C_processes','組織両利き採用研究','2004','macro','adoption','ambidextrous_adoption','["O''Reilly, C.A.", "Tushman, M.L.", "Gibson, C.B."]','["O''Reilly & Tushman (2008) Ambidexterity", "Gibson & Birkinshaw (2004) Antecedents of ambidexterity"]','両利き経営,深化と探索,イノベーション採用ガバナンス,組織両利き','ambidextrous organization,exploitation and exploration,innovation adoption governance,organizational ambidexterity'),
('inno_diff_506','CBDC（中央銀行デジタル通貨）採用研究','Central Bank Digital Currency Adoption Research','中国デジタル人民元・ECB電子ユーロ・Fedcoin構想等CBDCへの消費者・金融機関採用を分析した研究群。民間銀行預金代替への懸念・プライバシー・金融システム安定性・クロスボーダー決済改善が採用規定因として確認されている。','CBDC設計政策と国際通貨体制改革に実証的根拠を提供した。','diffusion_adoption_user','C_processes','CBDC採用研究','2020','macro','adoption','cbdc_adoption','["Auer, R.", "Cornelli, G.", "Frost, J."]','["Auer et al. (2020) CBDC design", "Frost et al. (2020) CBDC financial stability"]','CBDC,デジタル人民元,電子ユーロ,中央銀行デジタル通貨','CBDC,digital yuan,digital euro,central bank digital currency'),
('inno_diff_507','AIによる気候変動適応技術採用研究','AI-Driven Climate Change Adaptation Technology Adoption Research','AIを活用した洪水予測・熱中症アラート・農業気候適応ツール・都市熱島対策への行政・農業従事者採用を分析した研究群。予測精度・データ地域適合性・意思決定への統合・気候脆弱性が採用規定因として確認されている。','気候変動適応政策とSDGs実施の科学的根拠を提供した。','diffusion_adoption_user','C_processes','気候適応技術採用研究','2019','meso','adoption','climate_adaptation_adoption','["Rolnick, D.", "Donti, P.L.", "Kaack, L.H."]','["Rolnick et al. (2019) Tackling climate with ML", "Donti & Kolter (2021) Machine learning for climate"]','AI気候適応,洪水予測AI,農業気候適応,都市熱島対策','AI climate adaptation,flood prediction AI,agricultural climate adaptation,urban heat island'),
('inno_diff_508','ソーシャルスコアリング採用研究（企業評価）','Social Scoring Adoption Research in Corporate Evaluation','企業のESGスコアリング・サプライヤー評価・消費者信用スコアリングシステムへの金融機関・購買担当者採用を分析した研究群。スコアの比較可能性・透明性・集計方法差異・スコア依存の落とし穴が採用規定因として確認されている。','ESG評価標準化政策と企業持続可能性開示規制に実証的根拠を提供した。','diffusion_adoption_user','C_processes','ESGスコアリング採用研究','2016','meso','adoption','esg_scoring_adoption','["Berg, F.", "Kölbel, J.F.", "Rigobon, R."]','["Berg et al. (2022) Aggregate confusion ESG", "Rigobon et al. (2021) ESG data divergence"]','ESGスコアリング,サプライヤー評価,社会信用,持続可能性評価','ESG scoring,supplier evaluation,social credit,sustainability assessment'),
('inno_diff_509','デジタル都市計画ツール採用研究','Digital Urban Planning Tool Adoption Research','CityGML・City OS・参加型GIS・AIゾーニング支援ツールへの都市計画担当者・市民採用を分析した研究群。データ品質・市民参加の真正性・意思決定権限・行政デジタル能力が採用規定因として確認されている。','デジタル都市計画政策と参加型ガバナンス設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','デジタル都市計画採用研究','2016','meso','adoption','urban_planning_digital_adoption','["Geertman, S.", "Stillwell, J.", "Ferreira, J."]','["Geertman & Stillwell (2009) Planning support systems", "Ferreira et al. (2015) City Induction"]','デジタル都市計画,CityGML,参加型GIS,AIゾーニング','digital urban planning,CityGML,participatory GIS,AI zoning'),
('inno_diff_510','ウォーターフットプリント計測採用研究','Water Footprint Measurement Adoption Research','製品・組織のウォーターフットプリント計測・バーチャルウォーター分析ツールへの企業・農業者採用を分析した研究群。計測標準化・流域文脈データ・水不足地域への適用・報告コストが採用規定因として確認されている。','水資源管理政策と企業水リスク戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','水計測採用研究','2012','meso','adoption','water_accounting_adoption','["Hoekstra, A.Y.", "Chapagain, A.K.", "Aldaya, M.M."]','["Hoekstra et al. (2011) Water footprint assessment manual", "Chapagain & Hoekstra (2004) Water footprints"]','ウォーターフットプリント,バーチャルウォーター,水資源管理,水リスク','water footprint,virtual water,water resource management,water risk'),
('inno_diff_511','インタラクティブTV採用研究','Interactive Television Adoption Research','HbbTV・スマートTV・第二スクリーン体験・連動型広告への視聴者採用を分析した研究群。コンテンツ関連性・操作の直感性・個人化・放送/通信統合が採用規定因として確認されている。','放送デジタル変革政策とコンテンツ産業のOTT移行戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','インタラクティブTV採用研究','2010','micro','adoption','interactive_tv_adoption','["Chorianopoulos, K.", "Lekakos, G.", "Perdikouri, A."]','["Chorianopoulos & Lekakos (2008) ITV applications", "Perdikouri et al. (2011) Interactive TV"]','インタラクティブTV,HbbTV,スマートTV,OTT採用','interactive TV,HbbTV,smart TV,OTT adoption'),
('inno_diff_512','デジタルモデリング・シミュレーション採用研究（工学）','Digital Modeling and Simulation Adoption Research in Engineering','FEA（有限要素解析）・CFD・マルチフィジクスシミュレーションソフトウェアの設計エンジニア採用を分析した研究群。計算コスト・モデル検証手順・物理試験との代替可能性・エンジニアの計算スキルが採用規定因として確認されている。','製品開発工期短縮と設計最適化政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','工学シミュレーション採用研究','2005','meso','adoption','simulation_engineering_adoption','["Zienkiewicz, O.C.", "Taylor, R.L.", "Ferziger, J.H."]','["Zienkiewicz & Taylor (2000) FEM", "Ferziger et al. (2020) CFD fundamentals"]','FEA,CFD,シミュレーション採用,デジタルモデリング','FEA,CFD,simulation adoption,digital modeling'),
('inno_diff_513','継続的インテグレーション・デリバリー（CI/CD）採用研究','Continuous Integration and Delivery Adoption Research','GitHub Actions・Jenkins・CircleCI等CI/CDパイプラインへの開発組織採用を分析した研究群。リリース頻度向上・バグ早期検出・デプロイ自動化・組織文化変革が採用効果として確認されている。DevOps成熟度との相関も分析されている。','ソフトウェア開発生産性政策とDevOps教育プログラム設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','CI/CD採用研究','2015','meso','adoption','devops_adoption','["Kim, G.", "Humble, J.", "Willis, J."]','["Kim et al. (2016) DevOps Handbook", "Humble & Farley (2010) Continuous Delivery"]','CI/CD,DevOps,継続的デリバリー,GitHub Actions','CI/CD,DevOps,continuous delivery,GitHub Actions'),
('inno_diff_514','採用研究の再現性と蓄積知識の信頼性評価研究','Replication and Knowledge Accumulation Reliability in Adoption Research','TAM・UTAUT等採用研究の主要命題を再現実証した研究群。多くの研究が方法論的問題（測定不変性・出版バイアス・過度な自由度）を抱え、蓄積知見の信頼性が問われていることを体系的に示した研究レビュー。採用研究のオープンサイエンス化を促した。','採用研究の科学的信頼性向上と方法論標準化に貢献した重要なメタ科学的研究群。','diffusion_adoption_user','C_processes','採用研究方法論・科学哲学','2018','micro','adoption','replication_adoption_research','["Dwivedi, Y.K.", "Rana, N.P.", "Williams, M.D."]','["Dwivedi et al. (2019) Re-examining TAM", "Rana et al. (2017) IS adoption review replication"]','採用研究再現性,TAM批判,出版バイアス,メタ科学','adoption research replication,TAM critique,publication bias,meta-science');
